mapper.sql:
/* wms-outbound-obdlvrysbmmgmt-sql-oracle.xml - selectDlvrySbmSql - 택배접수 관리 - 택배접수 정보 조회 */ SELECT 0 AS CHK /*체크박스*/ , OBHD.CTKEY /*센터코드*/ , OBHD.OWKEY /*화주코드*/ , OBHD.OBHDKEY /*릴리즈코드*/ , OBHD.WAHDKEY /*웨이브공통코드*/ , OBHD.OBHDTYPECD /*출고헤더유형코드*/ , OBHD.OBSTATUSCD /*출고상태코드*/ , OBHD.OBHDDAY /*출고예정일시*/ , pkg_crypto$decrypt(OBHD.ORDNM, #{encKey}) AS ORDNM /*주문자명*/ , pkg_crypto$decrypt(OBHD.RCPPRSNNM, #{encKey}) AS RCPPRSNNM /*수령인명*/ , pkg_crypto$decrypt(OBHD.RCPPRSNTELNO, #{encKey}) AS RCPPRSNTELNO /*전화번호*/ , pkg_crypto$decrypt(OBHD.RCPPRSNADDR1, #{encKey}) AS RCPPRSNADDR1 /*주소1*/ , OBHD.DLVYMSG /* 배송메세지 */ , OBHD.DLVRYCORPCD /*택배사코드*/ , COALESCE(HJSBM.WBLNO, OBHD.WBLNO) AS WBLNO /*운송장번호*/ , OBHD.DLVRYPRGRSTATUSCD /*택배진행상태코드*/ , HJSBM.CBMURKEY /*접수자*/ , HJSBM.CBMDATE /*접수일시*/ , HJSBM.ERRMSG /*오류메세지*/ , TRIM(OBHD.RCPPRSNADDR1) || ' ' || TRIM(OBHD.RCPPRSNADDR2) AS ADDRESS /*주소_prWblAPI송신용데이터*/ , OBHD.RCPPRSNZIPCD /*수령인우편번호_prWblAPI송신용데이터*/ FROM TWORK_INFO_OB_HD OBHD /*출고공통정보*/ INNER JOIN TWORK_INFO_OB_DT OBDT /*출고상세정보*/ ON OBHD.CTKEY = OBDT.CTKEY AND OBHD.OWKEY = OBDT.OWKEY AND OBHD.OBHDKEY = OBDT.OBHDKEY LEFT OUTER JOIN TWORK_INFO_HANJIN_SBM HJSBM /*한진택배 접수정보*/ ON OBHD.CTKEY = HJSBM.CTKEY AND OBHD.OWKEY = HJSBM.OWKEY AND OBHD.OBHDKEY = HJSBM.OBHDKEY WHERE 1=1 AND
#{SEARCH_CONDITION}
AND OBHD.OWKEY = #{sowkey}
AND OBHD.OBHDTYPECD IN ('10','20') GROUP BY OBHD.CTKEY , OBHD.OWKEY , OBHD.OBHDKEY , OBHD.WAHDKEY , OBHD.OBHDTYPECD , OBHD.OBSTATUSCD , OBHD.OBHDDAY , OBHD.ORDNM , OBHD.RCPPRSNNM , OBHD.RCPPRSNTELNO , OBHD.RCPPRSNADDR1 , OBHD.RCPPRSNADDR2 , OBHD.DLVYMSG , OBHD.RCPPRSNZIPCD , OBHD.DLVRYCORPCD , OBHD.WBLNO , OBHD.DLVRYPRGRSTATUSCD , HJSBM.CBMURKEY , HJSBM.CBMDATE , HJSBM.ERRMSG , HJSBM.WBLNO ORDER BY OBHD.OBHDKEY

