/* wms-outbound-obdlvrysbmmgmt-sql-oracle.xml - selectDlvrySbmList - 택배접수 관리 - 택배접수 정보 조회 */
#{GRIDPAGING_ROWNUMTYPE_TOP}
SELECT *
  FROM (

)
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-outbound-obdlvrysbmmgmt-sql-oracle.xml - obDlvrySbmInfoSelect - 운송장출력 이력등록 대상 색인 */
SELECT SBM.CTKEY
	 , SBM.OWKEY
	 , OBHD.DLVRYCORPCD
	 , SBM.WBLNO
	 , SBM.OBHDKEY
FROM TWORK_INFO_OB_HD OBHD
	INNER JOIN TWORK_INFO_HANJIN_SBM SBM
		ON OBHD.CTKEY = SBM.CTKEY
		AND OBHD.OWKEY = SBM.OWKEY
		AND OBHD.OBHDKEY = SBM.OBHDKEY
WHERE SBM.CTKEY = #{ctkey}
	AND SBM.OWKEY = #{owkey}
   	AND SBM.OBHDKEY = #{obhdkey}
	AND SBM.WBLNO = #{wblno}

mapper.insert:
/* wms-outbound-obdlvrysbmmgmt-sql-oracle.xml - obDlvryWblPrHsInsert - 택배접수 관리 - 운송장 출력 이력정보 등록 */
INSERT INTO TWORK_INFO_WBL_PRHS (
    CTKEY
    , OWKEY
	, DLVRYCORPCD
	, WBLNO
	, OBHDKEY
	, PRSEQ
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
)
SELECT
    #{ctkey}
    , #{owkey}
	, #{dlvrycorpcd}
	, #{wblno}
	, #{obhdkey}
	, COALESCE(MAX(PRSEQ), 0) + 1
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
FROM TWORK_INFO_WBL_PRHS
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND DLVRYCORPCD = #{dlvrycorpcd}
AND WBLNO = #{wblno}

mapper.sql:
/* wms-outbound-obdlvrysbmmgmt-sql-oracle.xml - obDlvryWblPrHsSql - 택배접수 관리 - 운송장 출력 이력정보 SQL */
SELECT CTKEY /*센터 코드*/
	 , OWKEY /*화주 코드*/
	 , DLVRYCORPCD /*택배사 코드*/
	 , WBLNO /*운송장번호*/
	 , OBHDKEY /*릴리즈 코드*/
	 , INSERTDATE /*입력 일시*/
	 , INSERTURKEY /*입력자*/
  FROM TWORK_INFO_WBL_PRHS /*운송장 출력 이력 정보*/
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND DLVRYCORPCD = #{dlvrycorpcd}
   AND WBLNO = #{wblno}
   AND OBHDKEY = #{obhdkey}
 ORDER BY PRSEQ

