mapper.update:
/* wms-outbound-obdlvrysbmmgmt-sql-oracle.xml - updateWaHdWblNo - 택배접수 관리 > 운송장번호 등록 - 웨이브 헤더에 택배사 코드 업데이트 */
UPDATE TWORK_INFO_WA_HD
   SET DLVRYCORPCD = #{dlvrycorpcd}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND WAHDKEY = #{wahdkey}
